---@class LDisplayBase
local LDisplayBase = LxClass("LDisplayBase",nil)

local typeofGameObject = typeof(UnityEngine.GameObject)

-----------------------------------------------------------------
function LDisplayBase:LDisplayBase()
	--父对象
	self._parentTrans = nil
	--预制体transform
	self._displayTrans = nil

	--资源名字路径
	self._assetName = nil
	self._assetPath = nil

	self._defaultAssetName = nil
	self._defaultAssetPath = nil

	--资源分类标记
	self._resTag = nil

	--资源类型
	self._poolItemType = nil

	--加载完成函数
	self._loadedFunc = nil

	self._pool = nil
	self._bUsePool = false

	---@type LxResRequester
	self._resRequester = nil
end

function LDisplayBase:Create(parentTrans,assetPath,assentName,defaultAssetPath,defaultAssetName)
	self._parentTrans = parentTrans
	self._assetPath = assetPath
	self._assetName = assentName
	self._defaultAssetPath = defaultAssetPath
	self._defaultAssetName = defaultAssetName
	self:OnCreate()
end

-----------------------------------------------------------------
function LDisplayBase:GetAssetName()
	return self._assetName
end
-----------------------------------------------------------------
function LDisplayBase:SetLoadedFunction(func)
	self._loadedFunc = func
end

-----------------------------------------------------------------
function LDisplayBase:StartLoad()
	if string.isempty(self._assetName) or  string.isempty(self._assetPath) then
		printErrorN("asset name is nil")
		self:DoLoadFailFunc()
		return
	end
	if self._bUsePool and self._pool then
		local args = self._pool:MakeArgs(self._assetPath,self._assetName,self._resTag,self._poolItemType)
		self._poolArgs = args
		self._pool:MakeItemAsync(args,function(go,args)
			self:OnPoolInstantEnd(go,args)
		end)
	else
		local assetPath = self._assetPath
		self._isLoading = true
		if self._resRequester then
			self._resRequester:Dispose()
			self._resRequester = nil
		end
		self._resRequester = LxResUtil.GetAssetRequester(assetPath, typeofGameObject, function(obj)
			self._isLoading = false
			self:OnLoaded(obj)
		end)
		self._resRequester:StartRequester()
	end
end

function LDisplayBase:OnPoolInstantEnd(instantTrans,args)
	if not instantTrans or not CS.IsValidObject(instantTrans) then return end
	local parentTrans = self._parentTrans
	if self:IsDestroy() or not parentTrans or not CS.IsValidObject(parentTrans) then
		local bReturnPool = false
		if self._pool then
			bReturnPool = self._pool:ReturnItem(args:GetItemKey(),instantTrans)
		end
		if not bReturnPool and CS.IsValidObject(instantTrans) then
			local bundleName = CS.FormatBundleNameByPath(self._assetPath)
			--LxResUtil.DestroyObject(instantTrans, bundleName)
			LxResUtil.DestroyObject(instantTrans.gameObject)
		end
		return
	end
	self:InternalInitDisplayTrans(instantTrans.transform)
end

function LDisplayBase:OnLoaded(asset, assetName, bundleName)
	if not asset then
		self:DoLoadFailFunc()
		return 
	end
	local parentTrans = self._parentTrans
	if self:IsDestroy() or not parentTrans or not CS.IsValidObject(parentTrans) then
		self:DoLoadFailFunc()
		return
	end

	if CS.IsWebGL() then
		if LGameSettings.isFrameInstantiate then
			self.isInstantiateComplete = nil
			local data = InstantObjectData.GetInstantObjectData(asset, function(assetInstant)
				self:InternalInitDisplayTrans(assetInstant.transform)
				assetInstant = nil
			end, bundleName, self._assetName)
			LDisplayCtrl.AddDisplay(data)
			return
		end
	end

	--local assetInstant = LxResUtil.NewObject(asset,bundleName)
	local assetInstant = LxResUtil.NewObject(asset)
	assetInstant.name = self._assetName
	asset = nil

	self:InternalInitDisplayTrans(assetInstant.transform)
end


function LDisplayBase:InternalInitDisplayTrans(assetTrans)
	if CS.IsWebGL() then
		if LGameSettings.isFrameInstantiate then
			self.isInstantiateComplete = true
		end
	end

	CS.SetParentTrans(assetTrans,self._parentTrans)
	if self._displayTrans and not CS.IsNullObject(self._displayTrans.gameObject) then
		--CS.DestroyObject(self._displayTrans.gameObject)
		LxResUtil.DestroyObject(self._displayTrans.gameObject)
	end

	self._displayTrans = assetTrans

	self:OnDpReady()

	local endFunc = self._loadedFunc
	self._loadedFunc = nil
	if endFunc ~= nil then
		endFunc(self)
	end
end
-----------------------------------------------------------------
function LDisplayBase:SetUsePool(bUse)
	self._bUsePool = bUse
end

function LDisplayBase:SetPool(simplePool)
	self._pool = simplePool
end

function LDisplayBase:IsUsePool()
	return self._bUsePool
end

-----------------------------------------------------------------
function LDisplayBase:Destroy()
	if self:IsDestroy() then
		return
	end

	if(self._resRequester ~= nil) then
		self._resRequester:Dispose()
		self._resRequester = nil
	end

	if CS.IsWebGL() then
		if LGameSettings.isFrameInstantiate then
			self.isInstantiateComplete = nil
		end
	end

	self:OnDestroy()
	local bReturnPool = false
	if self:IsDpValid() then	
		if self._bUsePool and self._poolArgs and self._pool then
			bReturnPool = self._pool:ReturnItem(self._poolArgs:GetItemKey(),self._displayTrans)
		end 	
		if not bReturnPool and CS.IsValidObject(self._displayTrans) then
			local assetPath = self._assetPath
			local bundleName = CS.FormatBundleNameByPath(assetPath)
			--LxResUtil.DestroyObject(self._displayTrans,bundleName)
			LxResUtil.DestroyObject(self._displayTrans.gameObject)
		end
	end
	self._displayTrans = nil 
	
	local assetPath = self._assetPath
	table.removeall(self)
	self._assetPath = assetPath
	self._isDestroy = true
end
